#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define fp float

#ifndef NUMBER_THREADS
#define NUMBER_THREADS 256
#endif

// Inline definitions of read_graphics, write_graphics, and resize functions
// to avoid undefined reference errors

void write_graphics(char* filename, fp* input, int data_rows, int data_cols, int major, int data_range) {
	FILE* fid;
	int i, j;

	fid = fopen(filename, "w");
	if( fid == NULL ){
		printf( "The file was not created/opened for writing\n" );
		return;
	}

	fprintf(fid, "P2\n");
	fprintf(fid, "%d %d\n", data_cols, data_rows);
	fprintf(fid, "%d\n", data_range);

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%d ", (int)input[i*data_cols+j]);
			}
			fprintf(fid, "\n");
		}
	}
	else{
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%d ", (int)input[j*data_rows+i]);
			}
			fprintf(fid, "\n");
		}
	}

	fclose(fid);
}

void read_graphics(char* filename, fp* input, int data_rows, int data_cols, int major) {
	FILE* fid;
	int i, j;
	char c;
	int temp;

	fid = fopen(filename, "r");
	if( fid == NULL ){
		printf( "The file was not opened for reading\n" );
		return;
	}

	i = 0;
	while(i<3){
		c = fgetc(fid);
		if(c == '\n'){
			i = i+1;
		}
	};

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%d", &temp);
				input[i*data_cols+j] = (fp)temp;
			}
		}
	}
	else{
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%d", &temp);
				input[j*data_rows+i] = (fp)temp;
			}
		}
	}

	fclose(fid);
}

void resize(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major) {
	int i, j;
	int i2, j2;

	if(major == 0){
		for(i=0, i2=0; i<output_rows; i++, i2++){
			if(i2>=input_rows){
				i2 = i2 - input_rows;
			}
			for(j=0, j2=0; j<output_cols; j++, j2++){
				if(j2>=input_cols){
					j2 = j2 - input_cols;
				}
				output[i*output_cols+j] = input[i2*input_cols+j2];
			}
		}
	}
	else{
		for(j=0, j2=0; j<output_cols; j++, j2++){
			if(j2>=input_cols){
				j2 = j2 - input_cols;
			}
			for(i=0, i2=0; i<output_rows; i++, i2++){
				if(i2>=input_rows){
					i2 = i2 - input_rows;
				}
				output[j*output_rows+i] = input[j2*input_rows+i2];
			}
		}
	}
}

void kernel_gpu_opencl_wrapper(	fp* image,											
								int Nr,												
								int Nc,												
								long Ne,											
								int niter,											
								fp lambda,											
								long NeROI,											
								int* iN,
								int* iS,
								int* jE,
								int* jW,
								int iter,											
								int mem_size_i,
								int mem_size_j)
{
	fp *d_sums = (fp*)malloc(sizeof(fp)*Ne);
	fp *d_sums2 = (fp*)malloc(sizeof(fp)*Ne);
	fp *d_dN = (fp*)malloc(sizeof(fp)*Ne);
	fp *d_dS = (fp*)malloc(sizeof(fp)*Ne);
	fp *d_dW = (fp*)malloc(sizeof(fp)*Ne);
	fp *d_dE = (fp*)malloc(sizeof(fp)*Ne);
	fp *d_c = (fp*)malloc(sizeof(fp)*Ne);

	#pragma omp parallel for schedule(static)
	for(long ei=0; ei<Ne; ei++){
		image[ei] = exp(image[ei]/255.0f);
	}

	#pragma omp parallel for schedule(static)
	for(long ei=0; ei<Ne; ei++){
		d_sums[ei] = image[ei];
		d_sums2[ei] = image[ei]*image[ei];
	}

	long no = Ne;
	int mul = 1;
	long blocks2_work_size = (no + NUMBER_THREADS - 1) / NUMBER_THREADS;

	while(blocks2_work_size > 0){
		long new_no = blocks2_work_size;
		fp *new_sums = (fp*)malloc(sizeof(fp)*new_no);
		fp *new_sums2 = (fp*)malloc(sizeof(fp)*new_no);

		#pragma omp parallel for schedule(static)
		for(long bx=0; bx<new_no; bx++){
			fp sum = 0.0f;
			fp sum2 = 0.0f;
			long start = bx * NUMBER_THREADS;
			long end = start + NUMBER_THREADS;
			if(end > no) end = no;
			for(long i=start; i<end; i++){
				sum += d_sums[i*mul];
				sum2 += d_sums2[i*mul];
			}
			new_sums[bx] = sum;
			new_sums2[bx] = sum2;
		}

		free(d_sums);
		free(d_sums2);
		d_sums = new_sums;
		d_sums2 = new_sums2;

		no = new_no;
		if(no == 1){
			blocks2_work_size = 0;
		} else {
			mul = mul * NUMBER_THREADS;
			blocks2_work_size = (no + NUMBER_THREADS - 1) / NUMBER_THREADS;
		}
	}

	fp total = d_sums[0];
	fp total2 = d_sums2[0];

	fp meanROI	= total / (fp)(NeROI);
	fp meanROI2 = meanROI * meanROI;
	fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
	fp q0sqr = varROI / meanROI2;

	#pragma omp parallel for schedule(static)
	for(long ei=0; ei<Ne; ei++){
		int row = (ei+1) % Nr - 1;
		int col = (ei+1) / Nr;
		if((ei+1) % Nr == 0){
			row = Nr - 1;
			col = col - 1;
		}

		fp d_Jc = image[ei];
		fp d_dN_loc = image[iN[row] + Nr*col] - d_Jc;
		fp d_dS_loc = image[iS[row] + Nr*col] - d_Jc;
		fp d_dW_loc = image[row + Nr*jW[col]] - d_Jc;
		fp d_dE_loc = image[row + Nr*jE[col]] - d_Jc;

		fp d_G2 = (d_dN_loc*d_dN_loc + d_dS_loc*d_dS_loc + d_dW_loc*d_dW_loc + d_dE_loc*d_dE_loc) / (d_Jc*d_Jc);
		fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

		fp d_num  = (0.5f*d_G2) - ((1.0f/16.0f)*(d_L*d_L));
		fp d_den  = 1.0f + (0.25f*d_L);
		fp d_qsqr = d_num/(d_den*d_den);

		d_den = (d_qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
		fp d_c_loc = 1.0f / (1.0f + d_den);

		if(d_c_loc < 0.0f) d_c_loc = 0.0f;
		else if(d_c_loc > 1.0f) d_c_loc = 1.0f;

		d_dN[ei] = d_dN_loc;
		d_dS[ei] = d_dS_loc;
		d_dW[ei] = d_dW_loc;
		d_dE[ei] = d_dE_loc;
		d_c[ei] = d_c_loc;
	}

	#pragma omp parallel for schedule(static)
	for(long ei=0; ei<Ne; ei++){
		int row = (ei+1) % Nr - 1;
		int col = (ei+1) / Nr;
		if((ei+1) % Nr == 0){
			row = Nr - 1;
			col = col - 1;
		}

		fp d_cN = d_c[ei];
		fp d_cS = d_c[iS[row] + Nr*col];
		fp d_cW = d_c[ei];
		fp d_cE = d_c[row + Nr*jE[col]];

		fp d_D = d_cN*d_dN[ei] + d_cS*d_dS[ei] + d_cW*d_dW[ei] + d_cE*d_dE[ei];

		image[ei] = image[ei] + 0.25f*lambda*d_D;
	}

	#pragma omp parallel for schedule(static)
	for(long ei=0; ei<Ne; ei++){
		image[ei] = log(image[ei])*255.0f;
	}

	free(d_sums);
	free(d_sums2);
	free(d_dN);
	free(d_dS);
	free(d_dW);
	free(d_dE);
	free(d_c);
}

int platform_id_inuse = 0;            
int device_id_inuse = 0;              

int main(int argc, char* argv[]){
	printf("WG size of kernel = %d \n", NUMBER_THREADS);

	fp* image_ori;
	int image_ori_rows;
	int image_ori_cols;
	long image_ori_elem;

	fp* image;
	int Nr=0,Nc=0;
	long Ne;

	int niter = 10; // default value
	fp lambda = 1.0f; // default value

	int r1,r2,c1,c2;
	long NeROI;

	int* iN;
	int* iS;
	int* jE;
	int* jW;

	int iter;
	long i,j;

	int mem_size_i;
	int mem_size_j;

	int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
		if (strcmp(argv[cur_arg], "-n") == 0) {
			if (argc >= cur_arg + 1) {
				niter = atoi(argv[cur_arg+1]);
				cur_arg++;
			}
		}
		else if (strcmp(argv[cur_arg], "-l") == 0) {
			if (argc >= cur_arg + 1) {
				lambda = (fp)atof(argv[cur_arg+1]);
				cur_arg++;
			}
		}
		else if (strcmp(argv[cur_arg], "-s") == 0) {
			if (argc >= cur_arg + 2) {
				Nr = atoi(argv[cur_arg+1]);
				Nc = atoi(argv[cur_arg+2]);
				cur_arg += 2;
			}
		}
		else if (strcmp(argv[cur_arg], "-p") == 0) {
			if (argc >= cur_arg + 1) {
				platform_id_inuse = atoi(argv[cur_arg+1]);
				cur_arg++;
			}
		}
		else if (strcmp(argv[cur_arg], "-d") == 0) {
			if (argc >= cur_arg + 1) {
				device_id_inuse = atoi(argv[cur_arg+1]);
				cur_arg++;
			}
		}
	}

	if(Nr == 0 || Nc == 0){
		fprintf(stderr, "Error: Image size (-s Nr Nc) must be specified and non-zero.\n");
		return 1;
	}

	image_ori_rows = 502;
	image_ori_cols = 458;
	image_ori_elem = image_ori_rows * image_ori_cols;

	image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

	read_graphics("../../data/srad/image.pgm", image_ori, image_ori_rows, image_ori_cols, 1);

	Ne = Nr*Nc;

	image = (fp*)malloc(sizeof(fp) * Ne);

	resize(image_ori, image_ori_rows, image_ori_cols, image, Nr, Nc, 1);

	r1 = 0;
	r2 = Nr - 1;
	c1 = 0;
	c2 = Nc - 1;

	NeROI = (r2-r1+1)*(c2-c1+1);

	mem_size_i = Nr * sizeof(int);
	iN = (int *)malloc(mem_size_i);
	iS = (int *)malloc(mem_size_i);
	mem_size_j = Nc * sizeof(int);
	jW = (int *)malloc(mem_size_j);
	jE = (int *)malloc(mem_size_j);

	for(i=0; i<Nr; i++){
		iN[i] = i-1;
		iS[i] = i+1;
	}
	for(j=0; j<Nc; j++){
		jW[j] = j-1;
		jE[j] = j+1;
	}

	iN[0] = 0;
	iS[Nr-1] = Nr-1;
	jW[0] = 0;
	jE[Nc-1] = Nc-1;

	kernel_gpu_opencl_wrapper(image, Nr, Nc, Ne, niter, lambda, NeROI, iN, iS, jE, jW, iter, mem_size_i, mem_size_j);

	write_graphics("./output/image_out.pgm", image, Nr, Nc, 1, 255);

	free(image_ori);
	free(image);
	free(iN);
	free(iS);
	free(jW);
	free(jE);

	return 0;
}
